import numpy as np
from causallearn.graph.GeneralGraph import GeneralGraph
from causallearn.graph.GraphNode import GraphNode

# =====================================================================
# EDITABLE: implement run_causal_discovery below
# =====================================================================
def run_causal_discovery(X: np.ndarray) -> GeneralGraph:
    """
    Hybrid evidence-weighted restricted-PC for linear-Gaussian CPDAG recovery.
    It combines a liberal/high-recall PC skeleton, a conservative PC skeleton,
    and a score-based GES proposal, then performs shrinkage Fisher-Z pruning and
    conservative collider orientation followed by Meek-style closure.
    """
    import math
    from itertools import combinations
    from causallearn.graph.Endpoint import Endpoint

    n, p = X.shape
    nodes = [GraphNode(f"X{i + 1}") for i in range(p)]

    def _mat(G):
        try:
            M = np.array(G.graph, dtype=int, copy=True)
        except Exception:
            M = np.zeros((p, p), dtype=int)
        if M.shape != (p, p):
            M = np.zeros((p, p), dtype=int)
        np.fill_diagonal(M, 0)
        return M

    def _adj(M):
        A = (M != 0) | (M.T != 0)
        np.fill_diagonal(A, False)
        return A

    def _run_pc(alpha):
        try:
            from causallearn.utils.PCUtils import SkeletonDiscovery, Meek, UCSepset
            from causallearn.utils.cit import CIT

            cg = SkeletonDiscovery.skeleton_discovery(X, alpha, CIT(X, "fisherz"), stable=True)
            try:
                cg = UCSepset.uc_sepset(cg, 0, uc_rule=0, uc_priority=2)
            except TypeError:
                cg = UCSepset.uc_sepset(cg, 0)
            cg = Meek.meek(cg)
            return cg.G if hasattr(cg, "G") else cg
        except Exception:
            try:
                from causallearn.search.ConstraintBased.PC import pc

                out = pc(X, alpha=alpha, indep_test="fisherz", stable=True, uc_rule=0, uc_priority=2)
                return out.G if hasattr(out, "G") else out
            except Exception:
                try:
                    from bench.pc import run_causal_discovery as pc_run

                    return pc_run(X)
                except Exception:
                    return GeneralGraph(nodes)

    def _run_ges():
        try:
            from bench.ges import run_causal_discovery as ges_run

            return ges_run(X)
        except Exception:
            try:
                from causallearn.search.ScoreBased.GES import ges

                out = ges(X, score_func="local_score_BIC")
                if isinstance(out, dict):
                    out = out.get("G", next(iter(out.values())))
                return out.G if hasattr(out, "G") else out
            except Exception:
                return _run_pc(0.05)

    ratio = n / max(p, 1)
    alpha_hi = 0.12 if ratio < 15 else (0.10 if ratio < 30 else 0.07)
    alpha_lo = 0.03 if ratio < 15 else 0.02

    M_hi = _mat(_run_pc(alpha_hi))
    M_lo = _mat(_run_pc(alpha_lo))
    M_sc = _mat(_run_ges())
    A_hi, A_lo, A_sc = _adj(M_hi), _adj(M_lo), _adj(M_sc)

    support = A_hi.astype(int) + 2 * A_lo.astype(int) + 2 * A_sc.astype(int)
    cand = A_hi | A_lo | A_sc
    np.fill_diagonal(cand, False)

    Z = X.astype(float) - X.mean(axis=0, keepdims=True)
    sd = Z.std(axis=0, ddof=1, keepdims=True)
    sd[sd < 1e-8] = 1.0
    Z = Z / sd
    R = (Z.T @ Z) / max(n - 1, 1)
    R = np.clip((R + R.T) / 2.0, -1.0, 1.0)
    np.fill_diagonal(R, 1.0)
    lam = float(min(0.25, max(0.02, p / float(max(n + p, 1)))))
    R = (1.0 - lam) * R + lam * np.eye(p)

    TAIL, ARROW = Endpoint.TAIL.value, Endpoint.ARROW.value

    def _is_dir(M, i, j):
        return M[i, j] == TAIL and M[j, i] == ARROW

    p_cache = {}

    def _fisher_p(i, j, S):
        a, b = (i, j) if i < j else (j, i)
        S = tuple(sorted(int(s) for s in S))
        key = (a, b, S)
        if key not in p_cache:
            idx = [a, b] + list(S)
            P = np.linalg.pinv(R[np.ix_(idx, idx)])
            denom = max(float(P[0, 0] * P[1, 1]), 1e-12)
            rho = float(np.clip(-P[0, 1] / math.sqrt(denom), -0.999999, 0.999999))
            z = abs(float(np.arctanh(rho))) * math.sqrt(max(n - len(S) - 3, 1))
            p_cache[key] = float(math.erfc(z / math.sqrt(2.0)))
        return p_cache[key]

    max_k = 4 if p <= 20 else 3
    pool_cap = 12 if p <= 20 else 10

    def _pool(i, j, adj_ref, forbid=()):
        forbid = set(forbid)
        base = [k for k in range(p) if k not in forbid and k not in (i, j) and (adj_ref[i, k] or adj_ref[j, k])]
        extra = [k for k in range(p) if k not in forbid and k not in (i, j) and k not in base]

        def score(k):
            return (support[i, k] + support[j, k], abs(R[i, k]) + abs(R[j, k]))

        base = sorted(base, key=score, reverse=True)
        if len(base) < pool_cap:
            base += sorted(extra, key=score, reverse=True)[: max(0, min(2, pool_cap - len(base)))]
        return base[: max(pool_cap, max_k + 1)]

    def _tau(i, j):
        return 0.015 + 0.015 * float(support[i, j])

    adj = cand.copy()
    sepsets = {}
    for ell in range(max_k + 1):
        snap = adj.copy()
        edges = [(i, j) for i in range(p) for j in range(i + 1, p) if snap[i, j]]
        for i, j in edges:
            pool = _pool(i, j, snap)
            if len(pool) < ell:
                continue
            best = None
            cutoff = _tau(i, j)
            for S in combinations(pool, ell):
                pv = _fisher_p(i, j, S)
                if pv > cutoff and (best is None or pv > best[0]):
                    best = (pv, S)
            if best is not None:
                adj[i, j] = adj[j, i] = False
                sepsets[(i, j)] = tuple(best[1])

    sep_cache = {}

    def _find_sep(i, j, forbid=None, cutoff=0.02):
        a, b = (i, j) if i < j else (j, i)
        key = (a, b, forbid)
        if key in sep_cache:
            return sep_cache[key]
        if (a, b) in sepsets and (forbid is None or forbid not in sepsets[(a, b)]):
            sep_cache[key] = sepsets[(a, b)]
            return sep_cache[key]
        pool = _pool(a, b, cand, () if forbid is None else (forbid,))
        for ell in range(min(max_k, len(pool)) + 1):
            best = None
            for S in combinations(pool, ell):
                pv = _fisher_p(a, b, S)
                if pv > cutoff and (best is None or pv > best[0]):
                    best = (pv, S)
            if best is not None:
                sep_cache[key] = tuple(best[1])
                return sep_cache[key]
        sep_cache[key] = None
        return None

    dirn = np.zeros((p, p), dtype=bool)

    def _undir(i, j):
        return adj[i, j] and not dirn[i, j] and not dirn[j, i]

    def _orient(i, j):
        if not adj[i, j] or dirn[j, i] or dirn[i, j]:
            return False
        dirn[i, j] = True
        dirn[j, i] = False
        return True

    for k in range(p):
        nbrs = [i for i in range(p) if adj[k, i]]
        for a in range(len(nbrs)):
            i = nbrs[a]
            for j in nbrs[a + 1 :]:
                if adj[i, j]:
                    continue
                sep = _find_sep(i, j, forbid=k, cutoff=0.025)
                prior = (_is_dir(M_lo, i, k) and _is_dir(M_lo, j, k)) or (
                    _is_dir(M_sc, i, k) and _is_dir(M_sc, j, k) and support[i, k] + support[j, k] >= 4
                )
                if sep is not None or prior:
                    _orient(i, k)
                    _orient(j, k)

    def _reach():
        reach = dirn.copy()
        for m in range(p):
            reach = reach | (reach[:, [m]] & reach[[m], :])
        np.fill_diagonal(reach, False)
        return reach

    changed = True
    while changed:
        changed = False
        reach = _reach()
        todo = []
        for i in range(p):
            for j in range(i + 1, p):
                if not _undir(i, j):
                    continue
                if any(dirn[k, i] and not adj[k, j] for k in range(p) if k not in (i, j)):
                    todo.append((i, j))
                    continue
                if any(dirn[k, j] and not adj[k, i] for k in range(p) if k not in (i, j)):
                    todo.append((j, i))
                    continue
                if reach[i, j] and not reach[j, i]:
                    todo.append((i, j))
                    continue
                if reach[j, i] and not reach[i, j]:
                    todo.append((j, i))
                    continue
                pa_j = [k for k in range(p) if k not in (i, j) and dirn[k, j] and _undir(i, k)]
                if any(not adj[a, b] for x, a in enumerate(pa_j) for b in pa_j[x + 1 :]):
                    todo.append((i, j))
                    continue
                pa_i = [k for k in range(p) if k not in (i, j) and dirn[k, i] and _undir(j, k)]
                if any(not adj[a, b] for x, a in enumerate(pa_i) for b in pa_i[x + 1 :]):
                    todo.append((j, i))
                    continue
        for a, b in todo:
            changed = _orient(a, b) or changed

    M = np.zeros((p, p), dtype=int)
    for i in range(p):
        for j in range(i + 1, p):
            if not adj[i, j]:
                continue
            if dirn[i, j]:
                M[i, j], M[j, i] = TAIL, ARROW
            elif dirn[j, i]:
                M[i, j], M[j, i] = ARROW, TAIL
            else:
                M[i, j] = M[j, i] = TAIL

    G = GeneralGraph(nodes)
    G.graph = M
    return G
