    """
    Screened BOSS-PC hybrid:
    1) obtain an order-search CPDAG proposal (BOSS/GRaSP fallback),
    2) add a high-recall shrinkage-screened skeleton (and PC when affordable),
    3) prune by restricted Fisher-Z tests with edge-adaptive cutoffs,
    4) orient using baseline directional priors, conservative collider tests,
       and Meek closure.
    """
    import math
    from itertools import combinations
    from causallearn.graph.Endpoint import Endpoint

    n, p = X.shape
    nodes = [GraphNode(f"X{i + 1}") for i in range(p)]
    TAIL, ARROW = Endpoint.TAIL.value, Endpoint.ARROW.value

    def _to_mat(G):
        try:
            M = np.array(G.graph, dtype=int, copy=True)
        except Exception:
            M = np.zeros((p, p), dtype=int)
        if M.shape != (p, p):
            M = np.zeros((p, p), dtype=int)
        np.fill_diagonal(M, 0)
        return M

    def _adj_of(M):
        A = (M != 0) | (M.T != 0)
        np.fill_diagonal(A, False)
        return A

    def _is_dir(M, i, j):
        return M[i, j] == TAIL and M[j, i] == ARROW

    def _run_boss_like():
        for module in ("bench.boss", "bench.grasp"):
            try:
                mod = __import__(module, fromlist=["run_causal_discovery"])
                G = mod.run_causal_discovery(X)
                return G.G if hasattr(G, "G") else G
            except Exception:
                pass
        return GeneralGraph(nodes)

    def _run_pc(alpha):
        try:
            from causallearn.search.ConstraintBased.PC import pc

            try:
                out = pc(
                    X,
                    alpha=alpha,
                    indep_test="fisherz",
                    stable=True,
                    uc_rule=0,
                    uc_priority=2,
                    show_progress=False,
                )
            except TypeError:
                out = pc(X, alpha=alpha, indep_test="fisherz", stable=True, uc_rule=0, uc_priority=2)
            return out.G if hasattr(out, "G") else out
        except Exception:
            try:
                from bench.pc import run_causal_discovery as pc_run

                return pc_run(X)
            except Exception:
                return GeneralGraph(nodes)

    ratio = n / max(p, 1)
    use_pc = p <= 20 or ratio >= 30
    alpha_pc = 0.12 if ratio < 20 else (0.10 if ratio < 35 else 0.07)

    M_b = _to_mat(_run_boss_like())
    M_p = _to_mat(_run_pc(alpha_pc)) if use_pc else np.zeros((p, p), dtype=int)
    A_b, A_p = _adj_of(M_b), _adj_of(M_p)

    Z = X.astype(float) - X.mean(axis=0, keepdims=True)
    sd = Z.std(axis=0, ddof=1, keepdims=True)
    sd[sd < 1e-8] = 1.0
    Z = Z / sd
    R = (Z.T @ Z) / max(n - 1, 1)
    R = np.clip((R + R.T) / 2.0, -1.0, 1.0)
    np.fill_diagonal(R, 1.0)
    lam = float(min(0.18, max(0.02, p / float(max(n + p, 1)))))
    R = (1.0 - lam) * R + lam * np.eye(p)

    P = np.linalg.pinv(R)
    d = np.sqrt(np.maximum(np.diag(P), 1e-12))
    F = -P / np.outer(d, d)
    F = np.clip((F + F.T) / 2.0, -0.999999, 0.999999)
    np.fill_diagonal(F, 0.0)

    score = 0.67 * np.abs(R) + 0.33 * np.abs(F)
    np.fill_diagonal(score, -1.0)
    top_m = min(p - 1, 5 if p <= 10 else (7 if p <= 20 else 10))
    A_scr = np.zeros((p, p), dtype=bool)
    if top_m > 0:
        for i in range(p):
            idx = np.argpartition(score[i], -top_m)[-top_m:]
            A_scr[i, idx] = True
    A_scr = A_scr | A_scr.T
    np.fill_diagonal(A_scr, False)

    r_thr = float(min(0.35, 1.35 * math.sqrt(max(math.log(max(p, 2) + 1.0) / max(n - 1, 1), 1e-12))))
    f_thr = 0.045 if p <= 20 else 0.055
    A_add = A_scr & ((np.abs(R) > r_thr) | (np.abs(F) > f_thr))
    cand = A_b | A_p | A_add
    np.fill_diagonal(cand, False)

